import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:5000/api',
});

export const AdminService = {
  // Artists
  getAllArtists: () => API.get('/artists'),
  getArtistById: (id: string) => API.get(`/artists/${id}`),
  upsertArtist: (data: any) => API.post('/import/artist', data),
  
  // Artworks
  getAllArtworks: () => API.get('/artworks'),
  upsertArtwork: (data: any) => API.post('/import/artwork', data),

  // Books
  getAllBooks: () => API.get('/books'),
  upsertBook: (data: any) => API.post('/books'),

  // Sections (FIXES TS2554)
  // We added a default empty string so calling it without an ID won't crash
  getAllSections: (bookId: string = '') => 
    bookId ? API.get(`/sections/book/${bookId}`) : API.get('/sections'),
  upsertSection: (data: any) => API.post('/sections'),

  // Series (FIXES TS2339)
  getAllSeries: () => API.get('/series'), // Added this line
  getSeriesByArtist: (artistId: string) => API.get(`/series/artist/${artistId}`),
  upsertSeries: (data: any) => API.post('/series'),
  
  // Taxonomy
  getAllTaxonomy: () => API.get('/taxonomy/all'), 
  upsertTheme: (data: any) => API.post('/taxonomy/theme', data),
  upsertTag: (data: any) => API.post('/taxonomy/tag', data),
};
